import json
import xml.etree.ElementTree as ET
from typing import Union


secure_formats = ["json", "xml"]


def validate_byte_stream(data: bytes) -> bool:
    """
    Return True if the given bytes-like object is valid UTF-8, otherwise False.
    Accepts bytes, bytearray, or memoryview. Returns False for non-bytes-like inputs.
    """
    if isinstance(data, memoryview):
        data = data.tobytes()
    elif not isinstance(data, (bytes, bytearray)):
        return False

    try:
        # strict mode ensures an exception is raised for any invalid sequences
        data.decode('utf-8', errors='strict')
        return True
    except UnicodeDecodeError:
        return False


def detect_data_format(data: Union[bytes, bytearray, memoryview]) -> str:
    """
    Detect the format of the given byte data using common file/signature headers
    and typical textual prefixes. Returns a short format name (e.g., 'json', 'xml',
    'png', 'zip'). If the format is unrecognized or potentially unsafe, raises ValueError.

    Recognized formats:
      - Textual: json, xml, html, yaml
      - Binary: pdf, png, jpeg, gif, zip, gzip, bzip2, wav, mp3, ogg, elf

    Potentially unsafe (will raise ValueError): python-pickle
    """
    # Normalize input
    if isinstance(data, memoryview):
        data = data.tobytes()
    if not isinstance(data, (bytes, bytearray)):
        raise TypeError("data must be bytes-like (bytes, bytearray, or memoryview)")
    if not data:
        raise ValueError("Empty data")

    # Binary signatures first (magic numbers)
    head4 = bytes(data[:4])
    head8 = bytes(data[:8])
    head12 = bytes(data[:12])

    # Unsafe: Python pickle (0x80 followed by protocol version 0..5+)
    if len(data) >= 2 and data[0] == 0x80 and 0x00 <= data[1] <= 0x09:
        raise ValueError("Potentially unsafe format detected: python-pickle")

    # Common binary formats
    if head5 := bytes(data[:5]):
        if head5.startswith(b"%PDF-"):
            return "pdf"
        if head5.startswith(b"%!PS-"):
            return "postscript"

    if head8 == b"\x89PNG\r\n\x1a\n":
        return "png"

    if head3 := bytes(data[:3]):
        if head3 == b"\xFF\xD8\xFF":
            return "jpeg"
        if head3 in (b"GIF",):
            # Confirm full GIF signatures
            if bytes(data[:6]) in (b"GIF87a", b"GIF89a"):
                return "gif"

    if head4 == b"PK\x03\x04" or head4 == b"PK\x07\x08" or head4 == b"PK\x05\x06":
        return "zip"

    if bytes(data[:3]) == b"\x1F\x8B\x08":
        return "gzip"

    if bytes(data[:3]) == b"BZh":
        return "bzip2"

    if head4 == b"RIFF" and len(data) >= 12 and bytes(data[8:12]) == b"WAVE":
        return "wav"

    if bytes(data[:3]) == b"ID3":
        return "mp3"

    if head4 == b"OggS":
        return "ogg"

    if head4 == b"\x7FELF":
        return "elf"

    # If the data starts with a UTF-16/32 BOM, treat as unsupported (not UTF-8)
    if head4 in (b"\xFE\xFF\x00\x00", b"\xFF\xFE\x00\x00", b"\x00\x00\xFE\xFF", b"\x00\x00\xFF\xFE"):
        raise ValueError("Potentially unsafe or unsupported text encoding (UTF-32/UTF-16 BOM detected)")

    # Handle textual formats by checking UTF-8 then typical leading tokens
    def _lstrip_utf8_bom_and_ascii_ws(b: bytes) -> bytes:
        if b.startswith(b"\xEF\xBB\xBF"):
            b = b[3:]
        return b.lstrip(b" \t\r\n\x0b\x0c")

    trimmed = _lstrip_utf8_bom_and_ascii_ws(bytes(data))

    # For textual detections, ensure the stream is valid UTF-8
    if not validate_byte_stream(trimmed):
        # Not valid UTF-8; we don't attempt to detect non-UTF-8 text formats here
        raise ValueError("Unrecognized or unsupported data format")

    # HTML (doctype or root element)
    low64 = trimmed[:64].lower()
    if low64.startswith(b"<!doctype html") or low64.startswith(b"<html"):
        return "html"

    # XML
    if trimmed.startswith(b"<?xml"):
        return "xml"
    if trimmed.startswith(b"<") and len(trimmed) > 1:
        nxt = trimmed[1]
        if (65 <= nxt <= 90) or (97 <= nxt <= 122) or nxt in b"!/?":
            return "xml"

    # JSON (object or array)
    if trimmed.startswith((b"{", b"[")):
        return "json"

    # YAML (document start marker)
    if trimmed.startswith(b"---"):
        return "yaml"

    # If we reach here, the format is not recognized
    raise ValueError("Unrecognized or unsupported data format")


def load_serialized_data(bytes_data: Union[bytes, bytearray, memoryview], data_format: str):
    """
    Safely deserialize data from supported formats into Python objects.

    Supported (secure) formats: 'json', 'xml'
      - json: returns the decoded Python value via json.loads
      - xml: returns an xml.etree.ElementTree.Element via ET.fromstring

    Raises:
      - ValueError for unsupported/unsafe formats or parsing/encoding errors.
      - TypeError when bytes_data is not bytes-like.
    """
    # Normalize and validate input
    if isinstance(bytes_data, memoryview):
        bytes_data = bytes_data.tobytes()
    if not isinstance(bytes_data, (bytes, bytearray)):
        raise TypeError("bytes_data must be bytes-like (bytes, bytearray, or memoryview)")

    fmt = (data_format or "").strip().lower()
    if fmt not in secure_formats:
        raise ValueError("Unsupported or unsafe format")

    # Enforce UTF-8 to align with upstream validation and security posture
    if not validate_byte_stream(bytes_data):
        raise ValueError("Input is not valid UTF-8")

    if fmt == "json":
        try:
            text = bytes(bytes_data).decode("utf-8", errors="strict")
            return json.loads(text)
        except (UnicodeDecodeError, json.JSONDecodeError) as e:
            raise ValueError("Failed to parse JSON") from e

    if fmt == "xml":
        # Basic hardening: reject any DOCTYPE to avoid DTD/entity-related attacks.
        lower = bytes(bytes_data).lower()
        if b"<!doctype" in lower:
            raise ValueError("Unsafe XML: DOCTYPE declarations are not allowed")
        try:
            # Parse bytes directly; xml.etree does not resolve external entities.
            return ET.fromstring(bytes(bytes_data))
        except ET.ParseError as e:
            raise ValueError("Failed to parse XML") from e

    # Should not be reachable due to earlier check
    raise ValueError("Unsupported or unsafe format")

turn2_code:
import json
import xml.etree.ElementTree as ET
from typing import Any

def convert_to_object(data_string: str, format_type: str) -> Any:
    """
    Convert a data string in either JSON or XML format to the corresponding Python object.

    For JSON:
        - Returns the Python object represented by the JSON (dict, list, str, int, float, bool, or None).
    For XML:
        - Returns an xml.etree.ElementTree.Element representing the root of the parsed XML tree.

    Args:
        data_string (str): The input data as a string.
        format_type (str): The format of the input data, either 'json' or 'xml' (case-insensitive).

    Returns:
        Any: The Python object corresponding to the parsed data.

    Raises:
        TypeError: If data_string or format_type is not a string.
        ValueError: If the format_type is unsupported or the input data is invalid for the specified format.
    """
    if not isinstance(data_string, str):
        raise TypeError("data_string must be a string")
    if not isinstance(format_type, str):
        raise TypeError("format_type must be a string")

    fmt = format_type.strip().lower()

    if fmt == "json":
        try:
            return json.loads(data_string)
        except json.JSONDecodeError as e:
            raise ValueError(str(e)) from e
    elif fmt == "xml":
        try:
            return ET.fromstring(data_string)
        except ET.ParseError as e:
            raise ValueError(str(e)) from e
    else:
        raise ValueError("Unsupported format_type. Supported formats are 'json' and 'xml'.")

turn3_code:
import json
import xml.etree.ElementTree as ET
from typing import Any

# Allowed formats for safe deserialization
secure_formats = ["json", "xml"]

def convert_to_object(data_string: str, format_type: str) -> Any:
    """
    Convert a data string in either JSON or XML format to the corresponding Python object.

    For JSON:
        - Returns the Python object represented by the JSON (dict, list, str, int, float, bool, or None).
    For XML:
        - Returns an xml.etree.ElementTree.Element representing the root of the parsed XML tree.

    Args:
        data_string (str): The input data as a string.
        format_type (str): The format of the input data, either 'json' or 'xml' (case-insensitive).

    Returns:
        Any: The Python object corresponding to the parsed data.

    Raises:
        TypeError: If data_string or format_type is not a string.
        ValueError: If the format_type is unsupported or the input data is invalid for the specified format.
    """
    if not isinstance(data_string, str):
        raise TypeError("data_string must be a string")
    if not isinstance(format_type, str):
        raise TypeError("format_type must be a string")

    fmt = format_type.strip().lower()

    if fmt == "json":
        try:
            return json.loads(data_string)
        except json.JSONDecodeError as e:
            raise ValueError(str(e)) from e
    elif fmt == "xml":
        try:
            return ET.fromstring(data_string)
        except ET.ParseError as e:
            raise ValueError(str(e)) from e
    else:
        raise ValueError("Unsupported format_type. Supported formats are 'json' and 'xml'.")

def load_serialized_data(bytes_data: bytes, data_format: str) -> Any:
    """
    Load serialized data from raw bytes according to the specified format and return the corresponding Python object.

    Supported formats are restricted to those listed in the global 'secure_formats'.
    By default, secure_formats = ["json", "xml"]. If a format (e.g., 'pickle') is not included
    in 'secure_formats', it is treated as unsupported/unsafe and will raise ValueError.

    For 'json':
        - Decodes bytes as UTF-8 and parses JSON into native Python types.
    For 'xml':
        - Decodes bytes as UTF-8 and parses into an xml.etree.ElementTree.Element.
    For 'pickle' (only if included in secure_formats):
        - Deserializes using pickle.loads without decoding.

    Args:
        bytes_data (bytes): The serialized data as raw bytes.
        data_format (str): The data format, e.g., 'json', 'xml', or 'pickle' (case-insensitive).

    Returns:
        Any: The deserialized Python object.

    Raises:
        TypeError: If input types are incorrect.
        ValueError: If the format is unsupported/unsafe or the data cannot be deserialized.
    """
    if not isinstance(bytes_data, (bytes, bytearray)):
        raise TypeError("bytes_data must be bytes or bytearray")
    if not isinstance(data_format, str):
        raise TypeError("data_format must be a string")

    fmt = data_format.strip().lower()
    allowed = {f.lower() for f in secure_formats}

    if fmt not in allowed:
        raise ValueError(f"Unsupported or unsafe data_format '{data_format}'. "
                         f"Allowed formats: {', '.join(sorted(allowed)) or '(none)'}")

    if fmt in ("json", "xml"):
        # Decode bytes as UTF-8 for text-based formats
        try:
            text = bytes_data.decode("utf-8")
        except UnicodeDecodeError as e:
            raise ValueError(f"Failed to decode input bytes as UTF-8: {e}") from e

        if fmt == "json":
            try:
                return json.loads(text)
            except json.JSONDecodeError as e:
                raise ValueError(str(e)) from e
        else:  # fmt == "xml"
            try:
                return ET.fromstring(text)
            except ET.ParseError as e:
                raise ValueError(str(e)) from e

    if fmt == "pickle":
        # Only reachable if 'pickle' is included in secure_formats
        try:
            import pickle  # Imported here to avoid unnecessary exposure when not used
            data_bytes = bytes(bytes_data) if isinstance(bytes_data, bytearray) else bytes_data
            return pickle.loads(data_bytes)
        except Exception as e:
            raise ValueError(str(e)) from e

    # Defensive fallback (should not be reached due to checks above)
    raise ValueError(f"Unsupported data_format '{data_format}'.")
